/**
 * Notification model — core types for the notification system.
 *
 * Architecture: All notifications are triggered via EventBus events.
 * The NotificationService listens for events and dispatches to
 * NotificationAdapter implementations (email, webhook, SMS, etc.).
 *
 * Constraints:
 * - All adapters must implement the NotificationAdapter interface
 * - All notifications must originate from EventBus events
 * - No direct service-to-service calls for notifications
 */

/**
 * Supported notification channels. Each channel has a corresponding
 * adapter that implements NotificationAdapter.
 */
export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'in-app';

/**
 * Notification types representing the kind of event that triggered
 * the notification. Used for routing and template selection.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'welcome'
  | 'account-updated';

/**
 * Priority levels for notifications. Adapters may use this to
 * determine delivery urgency.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * Payload sent to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID */
  id: string;
  /** The type of notification (determines template/content) */
  type: NotificationType;
  /** Delivery channel */
  channel: NotificationChannel;
  /** Recipient identifier (email, phone, user ID depending on channel) */
  recipient: string;
  /** Notification subject line */
  subject: string;
  /** Notification body content */
  body: string;
  /** Priority level */
  priority: NotificationPriority;
  /** Timestamp when the notification was created */
  createdAt: Date;
  /** Optional metadata for adapter-specific needs */
  metadata?: Record<string, unknown>;
}

/**
 * Result returned by adapters after attempting delivery.
 */
export interface NotificationResult {
  /** Whether the notification was delivered successfully */
  success: boolean;
  /** The notification that was sent */
  notificationId: string;
  /** Channel that handled delivery */
  channel: NotificationChannel;
  /** Timestamp of delivery attempt */
  deliveredAt: Date;
  /** Error message if delivery failed */
  error?: string;
}

/**
 * A stored notification record with delivery status.
 */
export interface Notification {
  /** Unique notification ID */
  id: string;
  /** The type of notification */
  type: NotificationType;
  /** Delivery channel used */
  channel: NotificationChannel;
  /** Recipient identifier */
  recipient: string;
  /** Notification subject */
  subject: string;
  /** Notification body */
  body: string;
  /** Priority level */
  priority: NotificationPriority;
  /** Whether delivery succeeded */
  delivered: boolean;
  /** Error message if delivery failed */
  error?: string;
  /** When the notification was created */
  createdAt: Date;
  /** When delivery was attempted */
  deliveredAt?: Date;
}

/**
 * NotificationAdapter interface — the contract all delivery channel
 * adapters must implement.
 *
 * Architecture constraint: Every notification channel (email, webhook,
 * SMS, in-app) must have an adapter that implements this interface.
 * The NotificationService dispatches to adapters based on channel type.
 * Adapters handle only delivery — they do not decide what to send or when.
 *
 * To add a new notification channel:
 * 1. Add the channel name to NotificationChannel type in models/notification.ts
 * 2. Create an adapter in src/adapters/ that implements NotificationAdapter
 * 3. Register the adapter with NotificationService via registerAdapter()
 */

import type { NotificationPayload, NotificationResult, NotificationChannel } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this adapter's channel.
   * Must return a NotificationResult indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails instead of sending them.
 * Replace the send() method internals with a real email provider
 * (e.g., SendGrid, SES, SMTP) for production use.
 *
 * Implements: NotificationAdapter
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Sender email address */
  from: string;
  /** Reply-to address */
  replyTo?: string;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');

  constructor(private config: EmailConfig) {}

  /**
   * Send an email notification.
   *
   * Stub implementation: logs the email payload and returns success.
   * Replace with real email provider integration for production.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: "${payload.subject}" (from: ${this.config.from})`,
    );

    // Stub: In production, call your email provider here.
    // Example: await sendgrid.send({ to: payload.recipient, from: this.config.from, ... })

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
      deliveredAt: new Date(),
    };
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Architecture: Event-driven via EventBus (exclusively).
 * - Services emit events to EventBus
 * - NotificationService subscribes to relevant events
 * - Notifications are dispatched to registered NotificationAdapter implementations
 *
 * Constraints:
 * - ALL notification triggers come through EventBus subscriptions
 * - ALL delivery channels are NotificationAdapter implementations
 * - No direct service-to-service calls for notifications
 * - To add a new trigger: subscribe to a new event type in registerEventHandlers()
 * - To add a new channel: implement NotificationAdapter and call registerAdapter()
 *
 * Depends on:
 * - EventBus (event system) for receiving all events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationPriority,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is supported; registering a second
   * adapter for the same channel replaces the first.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to EventBus events that trigger notifications.
   * All notification triggers must be registered here.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.sendNotification({
      type: 'order-status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: 'normal',
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   * If no adapter is registered for the channel, the notification
   * is recorded as failed.
   */
  async sendNotification(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    priority: NotificationPriority;
    metadata?: Record<string, unknown>;
  }): Promise<Notification> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority: params.priority,
      createdAt: new Date(),
      metadata: params.metadata,
    };

    const adapter = this.adapters.get(params.channel);
    let notification: Notification;

    if (adapter) {
      const result = await adapter.send(payload);
      notification = {
        id: payload.id,
        type: payload.type,
        channel: payload.channel,
        recipient: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        priority: payload.priority,
        delivered: result.success,
        error: result.error,
        createdAt: payload.createdAt,
        deliveredAt: result.deliveredAt,
      };
    } else {
      this.logger.warn(`No adapter registered for channel: ${params.channel}`);
      notification = {
        id: payload.id,
        type: payload.type,
        channel: payload.channel,
        recipient: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        priority: payload.priority,
        delivered: false,
        error: `No adapter registered for channel: ${params.channel}`,
        createdAt: payload.createdAt,
      };
    }

    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} to ${params.recipient}: delivered=${notification.delivered}`);
    return notification;
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

